('make', 'Make', 'Create, run, and manage Make automation scenarios.',
 '1.0.0', 'automation',
 '[{"name":"list_scenarios","description":"List all automation scenarios in the Make account","parameters":{"type":"object","properties":{"limit":{"type":"number","minimum":1,"maximum":100,"description":"Max scenarios to return (default 20)"},"pg[offset]":{"type":"number","description":"Pagination offset"}},"additionalProperties":false}},{"name":"get_scenario","description":"Get detailed information about a specific scenario","parameters":{"type":"object","properties":{"scenarioId":{"type":"string","description":"Scenario ID (required)"}},"required":["scenarioId"],"additionalProperties":false}},{"name":"run_scenario","description":"Trigger an immediate execution of a scenario","parameters":{"type":"object","properties":{"scenarioId":{"type":"string","description":"Scenario ID (required)"},"data":{"type":"object","description":"Optional input data to pass to the scenario"}},"required":["scenarioId"],"additionalProperties":false}},{"name":"activate_scenario","description":"Activate (turn on) a scenario so it runs on its schedule","parameters":{"type":"object","properties":{"scenarioId":{"type":"string","description":"Scenario ID (required)"}},"required":["scenarioId"],"additionalProperties":false}},{"name":"deactivate_scenario","description":"Deactivate (pause) a scenario","parameters":{"type":"object","properties":{"scenarioId":{"type":"string","description":"Scenario ID (required)"}},"required":["scenarioId"],"additionalProperties":false}},{"name":"list_scenario_logs","description":"Get execution logs for a scenario","parameters":{"type":"object","properties":{"scenarioId":{"type":"string","description":"Scenario ID (required)"},"limit":{"type":"number","minimum":1,"maximum":100,"description":"Max logs to return (default 20)"}},"required":["scenarioId"],"additionalProperties":false}}]'::jsonb,
 'first-party', 'write', true, 10, true,
 'integration', 'nango', 'verified', 'in_process', 'api-key', 'make'),

('zapier', 'Zapier', 'List and manage Zaps and run actions via the Zapier API.',
 '1.0.0', 'automation',
 '[{"name":"list_zaps","description":"List all Zaps in the Zapier account with status and configuration","parameters":{"type":"object","properties":{"state":{"type":"string","enum":["on","off","draft"],"description":"Filter by Zap state"},"limit":{"type":"number","minimum":1,"maximum":100,"description":"Max Zaps to return (default 20)"},"offset":{"type":"number","description":"Pagination offset"}},"additionalProperties":false}},{"name":"get_zap","description":"Get detailed information about a specific Zap","parameters":{"type":"object","properties":{"zapId":{"type":"string","description":"Zap ID (required)"}},"required":["zapId"],"additionalProperties":false}},{"name":"list_apps","description":"List available apps (integrations) in Zapier","parameters":{"type":"object","properties":{},"additionalProperties":false}},{"name":"enable_zap","description":"Turn on a Zap so it starts processing triggers","parameters":{"type":"object","properties":{"zapId":{"type":"string","description":"Zap ID (required)"}},"required":["zapId"],"additionalProperties":false}},{"name":"disable_zap","description":"Turn off a Zap to stop processing triggers","parameters":{"type":"object","properties":{"zapId":{"type":"string","description":"Zap ID (required)"}},"required":["zapId"],"additionalProperties":false}}]'::jsonb,
 'first-party', 'write', true, 10, true,
 'integration', 'nango', 'verified', 'in_process', 'oauth2', 'zapier'),

('pipedrive', 'Pipedrive', 'Manage deals, contacts, activities, and pipelines in Pipedrive CRM.',
 '1.0.0', 'crm',
 '[{"name":"list_deals","description":"List deals with optional filtering and pagination","parameters":{"type":"object","properties":{"status":{"type":"string","enum":["open","won","lost","deleted","all_not_deleted"],"description":"Filter by deal status (default: all_not_deleted)"},"start":{"type":"number","description":"Pagination offset (default 0)"},"limit":{"type":"number","minimum":1,"maximum":500,"description":"Max deals to return (default 20)"},"sort":{"type":"string","description":"Sort field and direction (e.g. add_time DESC)"}},"additionalProperties":false}},{"name":"get_deal","description":"Get full details of a specific deal","parameters":{"type":"object","properties":{"dealId":{"type":"number","description":"Deal ID (required)"}},"required":["dealId"],"additionalProperties":false}},{"name":"create_deal","description":"Create a new deal in a pipeline","parameters":{"type":"object","properties":{"title":{"type":"string","description":"Deal title (required)"},"value":{"type":"number","description":"Deal monetary value"},"currency":{"type":"string","description":"Currency code (e.g. USD, EUR)"},"person_id":{"type":"number","description":"Contact person ID to link"},"org_id":{"type":"number","description":"Organization ID to link"},"pipeline_id":{"type":"number","description":"Pipeline ID (uses default if omitted)"},"stage_id":{"type":"number","description":"Stage ID within the pipeline"}},"required":["title"],"additionalProperties":false}},{"name":"update_deal","description":"Update an existing deal","parameters":{"type":"object","properties":{"dealId":{"type":"number","description":"Deal ID (required)"},"title":{"type":"string","description":"Updated title"},"value":{"type":"number","description":"Updated value"},"stage_id":{"type":"number","description":"Move to this stage"},"status":{"type":"string","enum":["open","won","lost","deleted"],"description":"Change deal status"},"won_time":{"type":"string","description":"Won timestamp (ISO 8601, for status=won)"},"lost_reason":{"type":"string","description":"Reason for losing (for status=lost)"}},"required":["dealId"],"additionalProperties":false}},{"name":"list_persons","description":"List contacts (persons) in Pipedrive","parameters":{"type":"object","properties":{"start":{"type":"number","description":"Pagination offset"},"limit":{"type":"number","minimum":1,"maximum":500,"description":"Max persons to return (default 20)"},"sort":{"type":"string","description":"Sort field and direction"}},"additionalProperties":false}},{"name":"create_person","description":"Create a new contact person","parameters":{"type":"object","properties":{"name":{"type":"string","description":"Full name (required)"},"email":{"type":"array","items":{"type":"object","properties":{"value":{"type":"string"},"label":{"type":"string"}},"required":["value"]},"description":"Email addresses"},"phone":{"type":"array","items":{"type":"object","properties":{"value":{"type":"string"},"label":{"type":"string"}},"required":["value"]},"description":"Phone numbers"},"org_id":{"type":"number","description":"Organization ID to link"}},"required":["name"],"additionalProperties":false}},{"name":"list_organizations","description":"List organizations in Pipedrive","parameters":{"type":"object","properties":{"start":{"type":"number","description":"Pagination offset"},"limit":{"type":"number","minimum":1,"maximum":500,"description":"Max orgs to return (default 20)"},"sort":{"type":"string","description":"Sort field and direction"}},"additionalProperties":false}},{"name":"list_activities","description":"List activities (calls, meetings, tasks)","parameters":{"type":"object","properties":{"start":{"type":"number","description":"Pagination offset"},"limit":{"type":"number","minimum":1,"maximum":500,"description":"Max activities to return (default 20)"},"type":{"type":"string","description":"Activity type filter"},"done":{"type":"number","enum":[0,1],"description":"Filter: 0=undone, 1=done"}},"additionalProperties":false}},{"name":"create_activity","description":"Create a new activity (call, meeting, task, etc.)","parameters":{"type":"object","properties":{"subject":{"type":"string","description":"Activity subject (required)"},"type":{"type":"string","description":"Activity type (required, e.g. call, meeting, task)"},"deal_id":{"type":"number","description":"Linked deal ID"},"person_id":{"type":"number","description":"Linked person ID"},"org_id":{"type":"number","description":"Linked organization ID"},"due_date":{"type":"string","description":"Due date (YYYY-MM-DD)"},"due_time":{"type":"string","description":"Due time (HH:MM)"},"duration":{"type":"string","description":"Duration (HH:MM)"},"note":{"type":"string","description":"Activity note/description"}},"required":["subject","type"],"additionalProperties":false}},{"name":"list_pipelines","description":"List all sales pipelines","parameters":{"type":"object","properties":{},"additionalProperties":false}},{"name":"list_stages","description":"List stages of a pipeline","parameters":{"type":"object","properties":{"pipeline_id":{"type":"number","description":"Pipeline ID (required)"}},"required":["pipeline_id"],"additionalProperties":false}},{"name":"search_items","description":"Global search across deals, persons, organizations, and products","parameters":{"type":"object","properties":{"term":{"type":"string","description":"Search term (required, min 2 chars)"},"item_types":{"type":"string","description":"Comma-separated types: deal, person, organization, product"},"limit":{"type":"number","minimum":1,"maximum":500,"description":"Max results (default 20)"}},"required":["term"],"additionalProperties":false}}]'::jsonb,
 'first-party', 'write', true, 20, true,
 'integration', 'nango', 'verified', 'in_process', 'oauth2', 'pipedrive'),

('apollo', 'Apollo', 'Search and enrich contacts, manage sequences, and track engagement with Apollo.io.',
 '1.0.0', 'sales',
 '[{"name":"search_people","description":"Search for people/contacts in the Apollo prospecting database (no credit cost)","parameters":{"type":"object","properties":{"q_person_title":{"type":"string","description":"Job title to search for"},"q_organization_name":{"type":"string","description":"Company name to filter by"},"person_locations":{"type":"array","items":{"type":"string"},"description":"Location filters (e.g. [\"United States\", \"France\"])"},"person_seniorities":{"type":"array","items":{"type":"string"},"description":"Seniority levels (e.g. [\"senior\", \"manager\", \"director\", \"vp\", \"c_suite\"])"},"per_page":{"type":"number","minimum":1,"maximum":100,"description":"Results per page (default 20)"},"page":{"type":"number","minimum":1,"description":"Page number (default 1)"}},"additionalProperties":false}},{"name":"enrich_person","description":"Enrich a person with full profile data (uses 1 credit)","parameters":{"type":"object","properties":{"email":{"type":"string","description":"Email address to enrich"},"first_name":{"type":"string","description":"First name (used with last_name + domain)"},"last_name":{"type":"string","description":"Last name (used with first_name + domain)"},"domain":{"type":"string","description":"Company domain (used with name)"}},"additionalProperties":false}},{"name":"search_organizations","description":"Search for companies/organizations in Apollo","parameters":{"type":"object","properties":{"q_organization_name":{"type":"string","description":"Organization name to search"},"organization_locations":{"type":"array","items":{"type":"string"},"description":"Location filters"},"organization_num_employees_ranges":{"type":"array","items":{"type":"string"},"description":"Employee count ranges (e.g. [\"1,10\", \"11,50\", \"51,200\"])"},"per_page":{"type":"number","minimum":1,"maximum":100,"description":"Results per page (default 20)"},"page":{"type":"number","minimum":1,"description":"Page number"}},"additionalProperties":false}},{"name":"enrich_organization","description":"Get detailed company info including tech stack, funding, and employee data","parameters":{"type":"object","properties":{"domain":{"type":"string","description":"Company domain (required, e.g. apollo.io)"}},"required":["domain"],"additionalProperties":false}},{"name":"create_contact","description":"Add a contact to your Apollo CRM","parameters":{"type":"object","properties":{"first_name":{"type":"string","description":"First name (required)"},"last_name":{"type":"string","description":"Last name (required)"},"email":{"type":"string","description":"Email address"},"organization_name":{"type":"string","description":"Company name"},"title":{"type":"string","description":"Job title"},"phone":{"type":"string","description":"Phone number"}},"required":["first_name","last_name"],"additionalProperties":false}},{"name":"search_contacts","description":"Search contacts in your Apollo CRM (saved contacts, not prospecting DB)","parameters":{"type":"object","properties":{"q_keywords":{"type":"string","description":"Keyword search"},"per_page":{"type":"number","minimum":1,"maximum":100,"description":"Results per page (default 20)"},"page":{"type":"number","minimum":1,"description":"Page number"}},"additionalProperties":false}},{"name":"list_sequences","description":"List email sequences in your Apollo account","parameters":{"type":"object","properties":{"per_page":{"type":"number","minimum":1,"maximum":100,"description":"Results per page (default 20)"},"page":{"type":"number","minimum":1,"description":"Page number"}},"additionalProperties":false}},{"name":"add_to_sequence","description":"Add contacts to an email sequence","parameters":{"type":"object","properties":{"sequenceId":{"type":"string","description":"Sequence ID (required)"},"contact_ids":{"type":"array","items":{"type":"string"},"description":"Array of contact IDs to add (required)"}},"required":["sequenceId","contact_ids"],"additionalProperties":false}}]'::jsonb,
 'first-party', 'write', true, 10, true,
 'integration', 'nango', 'verified', 'in_process', 'api-key', 'apollo')

